## 7️⃣ 错误处理

```go
// Go 没有 try-catch，用返回值处理错误⭐
import "errors"

// 方式1：fmt.Errorf
func divide(a, b float64) (float64, error) {
    if b == 0 {
        return 0, fmt.Errorf("除数不能为0，b=%f", b)
    }
    return a / b, nil
}

// 方式2：errors.New
func validate(age int) error {
    if age < 0 {
        return errors.New("年龄不能为负数")
    }
    return nil
}

// 方式3：自定义错误
type MyError struct {
    Code    int
    Message string
}

func (e *MyError) Error() string {
    return fmt.Sprintf("错误码%d: %s", e.Code, e.Message)
}

// 使用
result, err := divide(10, 0)
if err != nil {
    fmt.Println("出错了:", err)
    return
}
fmt.Println("结果:", result)

// panic 和 recover（类似异常，慎用）
func safeFunc() {
    defer func() {
        if r := recover(); r != nil {
            fmt.Println("捕获到panic:", r)
        }
    }()
    panic("出大事了！")
}
```

