## 8️⃣ 并发编程（Go 的核心优势）⭐

### Goroutine
```go
import (
    "fmt"
    "time"
    "sync"
)

// 基本 goroutine
func sayHello(name string) {
    fmt.Println("Hello", name)
}

func main() {
    go sayHello("Go")      // 启动一个 goroutine
    go sayHello("World")   // 再启动一个

    time.Sleep(time.Second) // 等待 goroutine 完成
}

// 使用 WaitGroup 等待
func main() {
    var wg sync.WaitGroup

    for i := 0; i < 5; i++ {
        wg.Add(1)
        go func(id int) {
            defer wg.Done()
            fmt.Printf("Goroutine %d 执行中\n", id)
        }(i)
    }

    wg.Wait() // 等待所有 goroutine 完成
    fmt.Println("全部完成")
}
```

### Channel
```go
// 基本 channel
func main() {
    ch := make(chan string)

    go func() {
        ch <- "Hello from goroutine!" // 发送
    }()

    msg := <-ch // 接收
    fmt.Println(msg)
}

// 带缓冲的 channel
ch := make(chan int, 3) // 缓冲区大小为3
ch <- 1
ch <- 2
ch <- 3

// 用 range 读取 channel
go func() {
    for i := 0; i < 5; i++ {
        ch <- i
    }
    close(ch) // 关闭 channel
}()

for value := range ch {
    fmt.Println(value)
}

// select 多路复用
select {
case msg := <-ch1:
    fmt.Println("从 ch1 收到:", msg)
case msg := <-ch2:
    fmt.Println("从 ch2 收到:", msg)
case <-time.After(3 * time.Second):
    fmt.Println("超时了")
}
```

