### 🔟 GORM 数据库操作

```go
import (
    "gorm.io/gorm"
    "gorm.io/driver/mysql"
)

type User struct {
    gorm.Model           // ID, CreatedAt, UpdatedAt, DeletedAt
    Name  string `gorm:"size:100;not null"`
    Email string `gorm:"uniqueIndex"`
    Age   int
}

func main() {
    // 连接数据库
    dsn := "root:password@tcp(127.0.0.1:3306)/mydb?charset=utf8mb4"
    db, err := gorm.Open(mysql.Open(dsn), &gorm.Config{})
    if err != nil {
        log.Fatal(err)
    }

    // 自动建表
    db.AutoMigrate(&User{})

    // 创建
    db.Create(&User{Name: "张三", Email: "zs@example.com", Age: 25})

    // 查询
    var user User
    db.First(&user, 1)                    // 按主键
    db.Where("name = ?", "张三").First(&user) // 条件查询

    // 查询多条
    var users []User
    db.Where("age > ?", 20).Find(&users)

    // 更新
    db.Model(&user).Update("Age", 26)
    db.Model(&user).Updates(User{Name: "李四", Age: 30})

    // 删除（软删除）
    db.Delete(&user, 1)
}
```

